#include <bits/stdc++.h>
#define fr first
#define sc second
using namespace std;
typedef pair<int,int> pii;

const int N=1e5+10,INF=1e8;

int n,m,a[N];
int dep[N],top[N],son[N],sz[N],fa[N],dfn[N],w[N],num,en[N];
int f[N][2],g[N][2];
vector<int> e[N];

struct Node{
    int a00,a01,a10,a11;
    Node operator*(Node x)const{
        Node res;
        res.a00=max(a00+x.a00,a01+x.a10);
        res.a01=max(a00+x.a01,a01+x.a11);
        res.a10=max(a10+x.a00,a11+x.a10);
        res.a11=max(a10+x.a01,a11+x.a11);
        return res;
    }
}t[N<<2];

void dfs1(int x,int lst){
    fa[x]=lst;
    dep[x]=dep[lst]+1;
    sz[x]=1;
    for(int y:e[x])
        if(y!=lst){
            dfs1(y,x);
            sz[x]+=sz[y];
            if(sz[y]>sz[son[x]])
                son[x]=y;
        }
    if(son[x]) en[x]=en[son[x]];
    else en[x]=x;
}

void dfs2(int x,int topx){
    top[x]=topx;
    dfn[x]=++num;
	w[num]=x;
    if(son[x])
        dfs2(son[x],topx);
    for(int y:e[x])
        if(y!=fa[x] && y!=son[x])
            dfs2(y,y);
}

void dfs3(int x){
    f[x][0]=0,f[x][1]=a[x];
    g[x][0]=g[x][1]=0;
    for(int y:e[x])
        if(y!=fa[x]){
            dfs3(y);
            f[x][0]+=max(f[y][0],f[y][1]);
            f[x][1]+=f[y][0];
            if(y!=son[x]){
                g[x][0]+=max(f[y][0],f[y][1]);
                g[x][1]+=f[y][0];
            }
        }
}

void build(int cur,int l,int r){
    if(l==r){
        t[cur]={g[w[l]][0],g[w[l]][0],g[w[l]][1]+a[w[l]],-INF};
        return;
    }
    int mid=l+r>>1;
    build(cur*2,l,mid);
    build(cur*2+1,mid+1,r);
    t[cur]=t[cur*2]*t[cur*2+1];
}

void modify(int cur,int l,int r,int x){
    if(l==r){
        t[cur]={g[w[l]][0],g[w[l]][0],g[w[l]][1]+a[w[l]],-INF};
        return;
    }
    int mid=l+r>>1;
    if(x<=mid) modify(cur*2,l,mid,x);
    else modify(cur*2+1,mid+1,r,x);
    t[cur]=t[cur*2]*t[cur*2+1];
}

Node query(int cur,int l,int r,int x,int y){
    if(x<=l && r<=y) return t[cur];
    int mid=l+r>>1;
    if(y<=mid) return query(cur*2,l,mid,x,y);
    if(x>mid) return query(cur*2+1,mid+1,r,x,y);
    return query(cur*2,l,mid,x,y)*query(cur*2+1,mid+1,r,x,y);
}

pii cal(int x){
	//printf("%d %d %d %d\n",x,dfn[x],en[x],dfn[en[x]]);
	if(x==en[x]) return make_pair(0,a[x]);
    Node tmp=query(1,1,n,dfn[x],dfn[en[x]]-1);
    return make_pair(max(tmp.a00,tmp.a01+a[en[x]]),max(tmp.a10,tmp.a11+a[en[x]]));
}

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
        scanf("%d",&a[i]);
    for(int i=1,u,v;i<n;i++){
        scanf("%d%d",&u,&v);
        e[u].push_back(v);
        e[v].push_back(u);
	}
    dfs1(1,0);
    dfs2(1,1);
    dfs3(1);
    build(1,1,n);
    while(m--){
        int x,y;
        scanf("%d%d",&x,&y);
        for(int p=top[x];fa[p];p=top[fa[p]]){
            p=top[p];
            pii tmp=cal(p);
            g[fa[p]][0]-=max(tmp.fr,tmp.sc);
            g[fa[p]][1]-=tmp.fr;
        }
        a[x]=y;
        modify(1,1,n,dfn[x]);
        for(int p=top[x];fa[p];p=top[fa[p]]){
            pii tmp=cal(p);
            g[fa[p]][0]+=max(tmp.fr,tmp.sc);
            g[fa[p]][1]+=tmp.fr;
            modify(1,1,n,dfn[fa[p]]);
        }
        pii tmp=cal(1);
        printf("%d\n",max(tmp.fr,tmp.sc));
    }
    return 0;
}
